"use client";

import Image from "next/image";
import { useCallback, useEffect, useState } from "react";
import { createPortal } from "react-dom";

type CaseStudyImageProps = {
  src: string;
  alt: string;
  className?: string;
};

export function CaseStudyImage({ src, alt, className = "" }: CaseStudyImageProps) {
  const [lightboxOpen, setLightboxOpen] = useState(false);
  const [aspectRatio, setAspectRatio] = useState<number | null>(null);

  const close = useCallback(() => setLightboxOpen(false), []);

  const onImageLoad = useCallback(
    (e: React.SyntheticEvent<HTMLImageElement>) => {
      const img = e.currentTarget;
      if (img.naturalWidth && img.naturalHeight) {
        setAspectRatio(img.naturalWidth / img.naturalHeight);
      }
    },
    []
  );

  useEffect(() => {
    setAspectRatio(null);
  }, [src]);

  useEffect(() => {
    if (!lightboxOpen) return;
    const handleEscape = (e: KeyboardEvent) => {
      if (e.key === "Escape") close();
    };
    document.addEventListener("keydown", handleEscape);
    document.body.style.overflow = "hidden";
    return () => {
      document.removeEventListener("keydown", handleEscape);
      document.body.style.overflow = "";
    };
  }, [lightboxOpen, close]);

  return (
    <>
      <button
        type="button"
        onClick={() => setLightboxOpen(true)}
        className={`group relative block w-full cursor-pointer overflow-hidden rounded-xl border border-white/15 bg-zinc-900 focus:outline-none focus:ring-2 focus:ring-zinc-500 focus:ring-offset-2 focus:ring-offset-[#080808] ${className}`}
        aria-label={`Expand ${alt}`}
      >
        <div
          className="relative w-full"
          style={
            aspectRatio != null
              ? { aspectRatio: `${aspectRatio}` }
              : { aspectRatio: "4/3" }
          }
        >
          <Image
            src={src}
            alt={alt}
            fill
            className="object-contain"
            sizes="900px"
            unoptimized={src.endsWith(".gif")}
            onLoad={onImageLoad}
          />
        </div>
      </button>

      {lightboxOpen &&
        typeof document !== "undefined" &&
        createPortal(
          <div
            className="fixed inset-0 z-[100] flex items-center justify-center bg-black/90 p-4"
            onClick={close}
            role="dialog"
            aria-modal="true"
            aria-label="Expanded image"
          >
            <button
              type="button"
              onClick={close}
              className="absolute right-4 top-4 z-10 rounded-full bg-zinc-800/90 px-4 py-2 text-sm font-medium text-zinc-200 transition hover:bg-zinc-700 focus:outline-none focus:ring-2 focus:ring-zinc-500"
              aria-label="Close"
            >
              Close
            </button>
            <div
              className="relative max-h-[90vh] max-w-[90vw]"
              onClick={(e) => e.stopPropagation()}
            >
              <Image
                src={src}
                alt={alt}
                width={1920}
                height={1080}
                className="max-h-[90vh] w-auto max-w-[90vw] object-contain"
                unoptimized={src.endsWith(".gif")}
              />
            </div>
          </div>,
          document.body
        )}
    </>
  );
}
